     1→import { createContext, useState, useEffect } from 'react';
     2→
     3→export const ThemeContext = createContext();
     4→
     5→export const ThemeProvider = ({ children }) => {
     6→    const [theme, setTheme] = useState(() => {
     7→        const saved = localStorage.getItem('theme');
     8→        if (saved === 'light' || saved === 'dark') return saved;
     9→        // default to system preference
    10→        return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
    11→    });
    12→
    13→    useEffect(() => {
    14→        document.documentElement.setAttribute('data-theme', theme);
    15→        localStorage.setItem('theme', theme);
    16→    }, [theme]);
    17→
    18→    // listen for system preference changes when no manual override exists
    19→    useEffect(() => {
    20→        const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
    21→        const handleChange = (e) => {
    22→            const saved = localStorage.getItem('theme');
    23→            // only auto-switch if user hasn't manually toggled yet
    24→            if (!saved) {
    25→                setTheme(e.matches ? 'dark' : 'light');
    26→            }
    27→        };
    28→        mediaQuery.addEventListener('change', handleChange);
    29→        return () => mediaQuery.removeEventListener('change', handleChange);
    30→    }, []);
    31→
    32→    const toggleTheme = () => {
    33→        setTheme((prev) => (prev === 'light' ? 'dark' : 'light'));
    34→    };
    35→
    36→    const value = { theme, toggleTheme };
    37→
    38→    return (
    39→        <ThemeContext.Provider value={value}>
    40→            {children}
    41→        </ThemeContext.Provider>
    42→    );
    43→};
